args.sparql:
SELECT ?leagueLabel WHERE {
  ?player p:P54 [ ps:P54 wd:Q19584; pq:P580 ?startCrawley; pq:P582 ?endCrawley ];
         wdt:P19 wd:Q239 .
  FILTER ( ?startCrawley <= "2016-05-31"^^xsd:dateTime && ?endCrawley >= "2015-08-01"^^xsd:dateTime )
  ?player p:P54 [ ps:P54 ?newTeam; pq:P580 ?startNew ].
  FILTER ( ?startNew > "2016-05-31"^^xsd:dateTime )
  ?newTeam wdt:P758 ?league .
  ?league rdfs:label ?leagueLabel .
  FILTER ( LANGMATCHES( LANG(?leagueLabel), "en" ) )
} LIMIT 1

